"""Records .wav files using Jibo's Audio Service """
import os
import json
from http_recorder import HttpRecorder


class AudioRecorder(HttpRecorder):
    """AudioRecorder Class"""

    def __init__(self, name, robot, output_dir, root, ui_queue):
        self.__url = 'http://' + str(robot) + ':8383/log/'
        self.__robot_directory = '/tmp/audio_data/'
        self.__robot_audio_bin = '/tmp/audiolog.bin'

        # Create request data for START
        self.__data_start = json.dumps({"logging": True})

        # Create request data for STOP
        self.__data_stop = json.dumps({"logging": False})

        # Call parent
        HttpRecorder.__init__(self, name, self.__url, self.__url,
                              self.__data_start, self.__data_stop,
                              robot, output_dir, root, ui_queue)

    def stop(self):
        """Call parent stop; Process audio files on robot.
        Grab files to local; Delete files on robot"""
        super(AudioRecorder, self).stop()

        if self.has_stopped:
            # Create /tmp/audio_data/ directory on robot
            channel = self.ssh.get_transport().open_session()
            channel.exec_command('mkdir ' + self.__robot_directory)

            # Extract audiolog.bin file on robot by running jibo-audio-dump-state command
            channel = self.ssh.get_transport().open_session()
            channel.exec_command('cd ' + self.__robot_directory + '; ' +
                                 '/usr/local/bin/jibo-audio-dump-state -i' + self.__robot_audio_bin)

            # Ship audio_data contents to local via rsync
            os.system('rsync -r -v --progress -e ssh root@' +
                      self.robot + ':' + self.__robot_directory + ' ' + self.directory)
            self.update_ui('Done audio file transfer', 'dark green')

            # Delete files on robot
            files = self.sftp.listdir(path=self.__robot_directory)
            for filename in files:
                self.sftp.remove(os.path.join(self.__robot_directory, filename))
            self.sftp.remove(self.__robot_audio_bin)

            # Update UI
            self.update_ui('Downloaded Files', 'dark green')
